import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import * as xlsx from "xlsx";

export async function POST(req: Request) {
    try {
        const formData = await req.formData();
        const file = formData.get("file") as File;
        const projectId = formData.get("projectId") as string;

        if (!file || !projectId) {
            return NextResponse.json(
                { error: "File and projectId are required" },
                { status: 400 }
            );
        }

        // Read the file buffer
        const bytes = await file.arrayBuffer();
        const buffer = Buffer.from(bytes);

        // Parse Excel
        const workbook = xlsx.read(buffer, { type: "buffer" });
        const sheetName = "Meetstaat";
        const boSheetName = "BO";

        if (!workbook.Sheets[sheetName]) {
            return NextResponse.json(
                { error: `Sheet "${sheetName}" not found in the uploaded file.` },
                { status: 400 }
            );
        }

        // Map categories from the BO sheet
        const techCodeToCategory: Record<string, string> = {};
        if (workbook.Sheets[boSheetName]) {
            const boSheet = workbook.Sheets[boSheetName];
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const boData = xlsx.utils.sheet_to_json(boSheet, { header: 1 }) as any[][];
            for (let i = 0; i < boData.length; i++) {
                const row = boData[i];
                if (row && row.length > 11) {
                    const code = row[2]; // Column "Code"
                    const tache = row[11]; // Column "Tâche"
                    if (code && typeof code === 'string' && tache && typeof tache === 'string') {
                        if (code !== 'Code') {
                            techCodeToCategory[code.trim()] = tache.trim();
                        }
                    }
                }
            }
        }

        // Map labor minutes from the CODES sheet
        const codeToMinutesMap: Record<string, number> = {};
        const codesSheetName = "CODES";
        if (workbook.Sheets[codesSheetName]) {
            const codesSheet = workbook.Sheets[codesSheetName];
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const codesData = xlsx.utils.sheet_to_json(codesSheet) as any[];
            for (const row of codesData) {
                let code = row["__EMPTY"];
                let montage = row["__EMPTY_2"];
                if (!code || !montage) {
                    code = row["CODE"] || row["Code"] || row["code"];
                    montage = row["MONTAGE"] || row["Montage"] || row["montage"];
                }
                if (code && typeof code === 'string' && montage && !isNaN(parseFloat(montage))) {
                    codeToMinutesMap[code.trim().toUpperCase()] = parseFloat(montage);
                }
            }
        }

        const sheet = workbook.Sheets[sheetName];
        // Read raw data to find headers
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const rawData = xlsx.utils.sheet_to_json(sheet, { header: 1 }) as any[][];

        let headerRowIdx = -1;
        for (let i = 0; i < Math.min(20, rawData.length); i++) {
            const row = rawData[i];
            if (row && row.some(cell => typeof cell === 'string' && cell.trim() === 'Description')) {
                headerRowIdx = i;
                break;
            }
        }

        if (headerRowIdx === -1) {
            return NextResponse.json({ error: "Could not find 'Description' header" }, { status: 400 });
        }

        // Convert sheet to json using found headers
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const jsonData = xlsx.utils.sheet_to_json(sheet, {
            range: headerRowIdx,
            defval: null
        }) as any[];

        // Prepare lookup object for existing Tasks (for Upsert logic)
        const existingTasksArr = await prisma.task.findMany({
            where: { projectId }
        });
        const existingTasks = new Map<string, { id: string, status: string }>();
        for (const t of existingTasksArr) {
            existingTasks.set(t.taskCode, t);
        }

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const tasksToCreate: any[] = [];
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const tasksToUpdate: any[] = [];
        const processedTaskCodes = new Set<string>();

        let currentParentDescription = "Non Catégorisé";

        for (const row of jsonData) {
            const description = row['Description'];
            const unit = row['Unité'];
            const qty = row['Qté'];
            
            const hasQty = qty !== null && qty !== undefined && !isNaN(parseFloat(qty));
            const isPureParent = description && !hasQty && (!unit || unit.toString().trim() === '');
            
            if (isPureParent) {
                currentParentDescription = String(description).trim();
            }

            const articleCode = row['N° Article'] || row['ArticleCode'] || undefined;
            const codeCol = row['CODE'];
            const techCode = row['TECH (via BO)'];

            let resolvedCategory = currentParentDescription !== "Non Catégorisé" ? currentParentDescription : "Autres";

            // MATERIAL DICTIONARY SMART CATEGORIZATION
            const materialDictionary = [
                { keywords: ['XGB', 'XVB', 'EXVB', 'Câble d\'alimentation', 'Câble pour tableaux'], category: 'Câblage lourd' },
                { keywords: ['FLEX', 'TUBE', 'B40H', 'B32H', 'B20H', 'B16H'], category: 'Tubage' },
                { keywords: ['F2', 'SVV', 'F3', 'UTP', 'FTP', 'FIBRE', 'COAX'], category: 'Courants faibles' },
                { keywords: ['CHEMIN DE CÂBLE', 'DALLE', 'TREILLIS', 'SUPPORT', 'CONSOLE'], category: 'Chemins de câbles' },
                { keywords: ['TABLEAU', 'TGBT', 'COFFRET', 'ARMOIRE'], category: 'Tableaux électriques' },
                { keywords: ['LUMINAIRE', 'SPOT', 'ECLAIRAGE', 'LED'], category: 'Éclairage' },
                { keywords: ['PRISE', 'INTERRUPTEUR', 'BOUTON POUSSOIR', 'DÉTECTEUR'], category: 'Appareillage' }
            ];

            const searchString = `${description || ''} ${articleCode || ''} ${codeCol || ''}`.toUpperCase();
            for (const dict of materialDictionary) {
                if (dict.keywords.some(kw => searchString.includes(kw.toUpperCase()))) {
                    resolvedCategory = dict.category;
                    break;
                }
            }

            const moMinKey = Object.keys(row).find(k => k.toLowerCase().includes('mo') && k.toLowerCase().includes('min/') && k.toLowerCase().includes('unité'));
            const minutesPerUnit = moMinKey ? row[moMinKey] : null;

            if (description && unit && qty !== null && qty !== undefined && minutesPerUnit !== null && minutesPerUnit !== undefined) {
                const qtyNum = parseFloat(qty);
                const minsNum = parseFloat(minutesPerUnit);

                if (!isNaN(qtyNum) && !isNaN(minsNum) && qtyNum > 0) {
                    // Parse hidden composite string if present (e.g. 13444&XGB3x2.5+2588&b20h)
                    if (codeCol && typeof codeCol === 'string' && codeCol.includes('&')) {
                        const parts = codeCol.split('+');

                        parts.forEach((part) => {
                            const [subQtyStr, ...descParts] = part.split('&');
                            const subDesc = descParts.join('&').trim();
                            const subQty = parseFloat(subQtyStr);

                            if (!isNaN(subQty) && subQty > 0 && subDesc) {
                                let subMinsPerUnit = 0;
                                let subUnit = 'm';
                                let subCategory = resolvedCategory;

                                // Apply dictionary to subDesc as well
                                const subSearchString = subDesc.toUpperCase();
                                for (const dict of materialDictionary) {
                                    if (dict.keywords.some(kw => subSearchString.includes(kw.toUpperCase()))) {
                                        subCategory = dict.category;
                                        break;
                                    }
                                }
                                
                                let finalSubDesc = subDesc;

                                if (subDesc.toLowerCase() === 'u') {
                                    subUnit = 'h';
                                    subMinsPerUnit = 60; // 1 hour = 60 minutes
                                    finalSubDesc = "Heures (u)";
                                } else {
                                    if (subDesc.toLowerCase() === 'pc') subUnit = 'pc';
                                    
                                    const mappedMins = codeToMinutesMap[subDesc.toUpperCase()];
                                    if (mappedMins !== undefined) {
                                        subMinsPerUnit = mappedMins;
                                    }
                                }

                                // Total component quantity = Parent Quantity * Component Quantity
                                const totalComponentQty = qtyNum * subQty;

                                // Create a unique taskCode for sub-components (e.g. 114&XGB5G16)
                                const uniqueTaskCode = `${techCode}_${finalSubDesc.replace(/\s+/g, '')}`;

                                processedTaskCodes.add(uniqueTaskCode);

                                const existingTask = existingTasks.get(uniqueTaskCode);
                                if (existingTask) {
                                    tasksToUpdate.push({
                                        id: existingTask.id,
                                        quantity: totalComponentQty,
                                        status: 'ACTIVE' // Reactivate if it was cancelled
                                    });
                                } else {
                                    tasksToCreate.push({
                                        projectId,
                                        taskCode: uniqueTaskCode,
                                        articleCode: articleCode ? String(articleCode) : undefined,
                                        category: subCategory,
                                        description: finalSubDesc,
                                        unit: subUnit,
                                        quantity: totalComponentQty,
                                        minutesPerUnit: subMinsPerUnit,
                                    });
                                }
                            }
                        });
                    } else {
                        // Standard singular item
                        let finalDesc = String(description);
                        if (codeCol && typeof codeCol === 'string' && !codeCol.includes('&')) {
                            const trimmedCode = codeCol.trim();
                            if (trimmedCode !== finalDesc) {
                                finalDesc = `${trimmedCode} - ${finalDesc}`;
                            }
                        }
                        
                        // Create a unique taskCode for singular items
                        const uniqueTaskCode = `${codeCol}_${finalDesc.replace(/\s+/g, '')}`;

                        processedTaskCodes.add(uniqueTaskCode);

                        const existingTask = existingTasks.get(uniqueTaskCode);
                        if (existingTask) {
                            tasksToUpdate.push({
                                id: existingTask.id,
                                quantity: qtyNum,
                                status: 'ACTIVE'
                            });
                        } else {
                            tasksToCreate.push({
                                projectId,
                                taskCode: uniqueTaskCode,
                                articleCode: articleCode ? String(articleCode) : undefined,
                                category: resolvedCategory,
                                description: finalDesc,
                                unit: String(unit),
                                quantity: qtyNum,
                                minutesPerUnit: minsNum,
                            });
                        }
                    }
                }
            }
        }

        if (tasksToCreate.length === 0 && tasksToUpdate.length === 0) {
            return NextResponse.json({ error: "No valid tasks found with Description, Unité, Qté, and MO min/unité." }, { status: 400 });
        }

        // Determine which tasks need to be CANCELLED (exist in DB but not in new parsed Excel)
        const tasksToCancel: string[] = [];
        for (const [code, task] of existingTasks.entries()) {
            if (!processedTaskCodes.has(code) && task.status === 'ACTIVE') {
                tasksToCancel.push(task.id);
            }
        }

        // Execute changes transactionally to ensure data integrity
        await prisma.$transaction(async (tx) => {
            // 1. Create new tasks
            if (tasksToCreate.length > 0) {
                await tx.task.createMany({
                    data: tasksToCreate
                });
            }

            // 2. Update existing tasks with NEW planned quantities
            for (const updateData of tasksToUpdate) {
                await tx.task.update({
                    where: { id: updateData.id },
                    data: {
                        quantity: updateData.quantity,
                        status: updateData.status
                    }
                });
            }

            // 3. Mark missing tasks as CANCELLED instead of deleting them
            if (tasksToCancel.length > 0) {
                await tx.task.updateMany({
                    where: { id: { in: tasksToCancel } },
                    data: { status: 'CANCELLED' }
                });
            }

            // 4. Log the Revision 
            await tx.revisionLog.create({
                data: {
                    projectId,
                    fileName: file.name,
                    changesMade: `Created: ${tasksToCreate.length}, Updated: ${tasksToUpdate.length}, Cancelled: ${tasksToCancel.length}`
                }
            });
        });

        return NextResponse.json({ 
            success: true, 
            summary: {
                created: tasksToCreate.length,
                updated: tasksToUpdate.length,
                cancelled: tasksToCancel.length
            }
        });

    } catch (error) {
        console.error("Upload error:", error);
        if (error instanceof Error) {
            return NextResponse.json({ error: error.message }, { status: 500 });
        }
        return NextResponse.json({ error: "Something went wrong" }, { status: 500 });
    }
}

