const xlsx = require('xlsx');

const workbook = xlsx.readFile('test_file.xlsm');
const sheet = workbook.Sheets['Meetstaat'];
const boSheet = workbook.Sheets['BO'];

let techCodeToCategory = {};
const boData = xlsx.utils.sheet_to_json(boSheet, { header: 1 });
for (let r of boData) {
    if (r && r.length > 11 && r[2] && r[11] && r[2] !== 'Code') {
        techCodeToCategory[r[2].trim()] = r[11].trim();
    }
}

const rawData = xlsx.utils.sheet_to_json(sheet, { header: 1 });
let headerRowIdx = -1;
for (let i = 0; i < Math.min(20, rawData.length); i++) {
    const row = rawData[i];
    if (row && row.some(cell => typeof cell === 'string' && cell.trim() === 'Description')) {
        headerRowIdx = i;
        break;
    }
}
const jsonData = xlsx.utils.sheet_to_json(sheet, { range: headerRowIdx, defval: null });

let hierarchy = {};
let categories = {};

for (const row of jsonData) {
    const description = row['Description'];
    const articleCode = row['N° Article'] || row['ArticleCode'] || "";
    const techCode = row['TECH (via BO)'];

    if (description && typeof articleCode === 'string') {
        // save to hierarchy
        hierarchy[articleCode] = description;
    }

    const qty = row['Qté'];
    const moMinKey = Object.keys(row).find(k => k.toLowerCase().includes('mo') && k.toLowerCase().includes('min/') && k.toLowerCase().includes('unité'));
    const mins = moMinKey ? row[moMinKey] : null;

    if (description && qty !== null && qty !== undefined && mins !== null && mins !== undefined) {
        let resolvedCategory = "Non Catégorisé";

        if (techCode && typeof techCode === 'string') {
            const mapped = techCodeToCategory[techCode.trim()];
            if (mapped) resolvedCategory = mapped;
        }

        // Fallback to parent
        if (resolvedCategory === "Non Catégorisé" && typeof articleCode === 'string') {
            const parts = articleCode.split('.');
            // Try to find the closest parent
            while (parts.length > 0) {
                parts.pop(); // remove last segment
                const parentCode = parts.join('.');
                if (hierarchy[parentCode]) {
                    resolvedCategory = hierarchy[parentCode];
                    break;
                }
            }
        }

        categories[resolvedCategory] = (categories[resolvedCategory] || 0) + 1;
    }
}

// Print results
let sorted = Object.entries(categories).sort((a, b) => b[1] - a[1]);
sorted.forEach(s => console.log(`${s[0]}: ${s[1]}`));

