const { PrismaClient } = require('@prisma/client');
const xlsx = require('xlsx');
const path = require('path');
const prisma = new PrismaClient();

async function seedPilotProject() {
    try {
        console.log("Starting Pilot Project Generation based on Excel...");

        // 1. Find the Excel file
        const filePath = path.join(__dirname, 'test_file.xlsm');
        const workbook = xlsx.readFile(filePath);
        const sheetName = 'Meetstaat';
        const sheet = workbook.Sheets[sheetName];
        if (!sheet) throw new Error("Meetstaat sheet not found.");
        const data = xlsx.utils.sheet_to_json(sheet, { header: 1 });

        // Build BO Mapping for Categories
        const boSheet = workbook.Sheets["BO"];
        const boData = xlsx.utils.sheet_to_json(boSheet, { header: 1, range: 6 });
        const techToBoMap = new Map();
        for (const row of boData) {
            const article = escapeObj(row[2]);
            const taskLevel1 = escapeObj(row[3]);
            if (article && taskLevel1) {
                techToBoMap.set(String(article).trim(), String(taskLevel1).trim());
            }
        }

        // Build CODES Mapping for Labor Minutes
        const codesSheet = workbook.Sheets["CODES"];
        const codesData = codesSheet ? xlsx.utils.sheet_to_json(codesSheet) : [];
        const codeToMinutesMap = new Map();
        for (const row of codesData) {
            let code = row["__EMPTY"];
            let montage = row["__EMPTY_2"];
            if (!code || !montage) {
                code = row["CODE"] || row["Code"] || row["code"];
                montage = row["MONTAGE"] || row["Montage"] || row["montage"];
            }
            if (code && typeof code === 'string' && montage && !isNaN(parseFloat(montage))) {
                codeToMinutesMap.set(code.trim().toUpperCase(), parseFloat(montage));
            }
        }

        // 2. Parse exactly like the upload route
        let headerRowIdx = -1;
        for (let i = 0; i < Math.min(20, data.length); i++) {
            const row = data[i];
            if (row && row.includes('Description') && row.includes('Unité')) {
                headerRowIdx = i;
                break;
            }
        }
        if (headerRowIdx === -1) throw new Error("Header row not found");
        
        const headers = data[headerRowIdx];
        const colDesc = headers.indexOf('Description');
        const colUnit = headers.indexOf('Unité');
        const colQty = headers.indexOf('Qté');
        const colArticle = headers.findIndex(h => h && h.includes('N° Article'));
        const colMins = headers.findIndex(h => h && typeof h === 'string' && (h.includes('MO') && (h.includes('heure') || h.includes('min/unit'))));
        const colCode = headers.indexOf('CODE');
        
        if (colMins === -1) {
            console.log(headers);
            throw new Error("Could not find Labor Minutes column!");
        }

        const validTasks = [];
        let currentParentDescription = "Non Catégorisé";

        for (let i = headerRowIdx + 1; i < data.length; i++) {
            const row = data[i];
            if (!row || row.length === 0) continue;
            
            const desc = row[colDesc];
            const qtyStr = parseFloat(row[colQty]);
            const unit = row[colUnit];
            
            const hasQty = !isNaN(qtyStr) && qtyStr > 0;
            const isPureParent = desc && !hasQty && !unit;

            // Parent detection: if it's a structural row without unit, it sets the current category
            let finalDesc = String(desc).trim();
            if (isPureParent) {
                currentParentDescription = finalDesc; 
            }

            if (!desc || !unit || isNaN(qtyStr)) continue;

            let minsStr = parseFloat(row[colMins]);
            if (isNaN(minsStr)) continue;
            if (headers[colMins].toLowerCase().includes('heure')) {
                minsStr = minsStr * 60; 
            }

            const rawArticle = row[colArticle] ? String(row[colArticle]).trim() : '';
            const techCode = row[colCode] ? String(row[colCode]).trim() : '';
            
            // Use the parent section as the category instead of the granular BO mapping
            let cat = currentParentDescription !== "Non Catégorisé" ? currentParentDescription : (techToBoMap.get(techCode) || "Autres");

            // MATERIAL DICTIONARY SMART CATEGORIZATION
            const materialDictionary = [
                { keywords: ['XGB', 'XVB', 'EXVB', 'Câble d\'alimentation', 'Câble pour tableaux'], category: 'Câblage lourd' },
                { keywords: ['FLEX', 'TUBE', 'B40H', 'B32H', 'B20H', 'B16H'], category: 'Tubage' },
                { keywords: ['F2', 'SVV', 'F3', 'UTP', 'FTP', 'FIBRE', 'COAX'], category: 'Courants faibles' },
                { keywords: ['CHEMIN DE CÂBLE', 'DALLE', 'TREILLIS', 'SUPPORT', 'CONSOLE'], category: 'Chemins de câbles' },
                { keywords: ['TABLEAU', 'TGBT', 'COFFRET', 'ARMOIRE'], category: 'Tableaux électriques' },
                { keywords: ['LUMINAIRE', 'SPOT', 'ECLAIRAGE', 'LED'], category: 'Éclairage' },
                { keywords: ['PRISE', 'INTERRUPTEUR', 'BOUTON POUSSOIR', 'DÉTECTEUR'], category: 'Appareillage' }
            ];

            const searchString = `${finalDesc || ''} ${rawArticle || ''} ${techCode || ''}`.toUpperCase();
            for (const dict of materialDictionary) {
                if (dict.keywords.some(kw => searchString.includes(kw.toUpperCase()))) {
                    cat = dict.category;
                    break;
                }
            }

            if (techCode && finalDesc.toLowerCase().includes('mm')) {
                finalDesc = `${techCode} - ${finalDesc}`;
            } else if (rawArticle && desc) {
                finalDesc = `${rawArticle} - ${finalDesc}`;
            }

            if (techCode && techCode.includes('&')) {
                const parts = techCode.split('+');
                
                parts.forEach((part) => {
                    const [subQtyStr, ...descParts] = part.split('&');
                    let subDesc = descParts.join('&').trim();
                    const subQty = parseFloat(subQtyStr);

                    if (!isNaN(subQty) && subQty > 0 && subDesc) {
                        let subMinsPerUnit = 0;
                        let subUnit = 'm';
                        let subCategory = cat; // inherit base category or dictionary match

                        // Apply dictionary specifically to subDesc
                        const subSearchString = subDesc.toUpperCase();
                        for (const dict of materialDictionary) {
                            if (dict.keywords.some(kw => subSearchString.includes(kw.toUpperCase()))) {
                                subCategory = dict.category;
                                break;
                            }
                        }
                        
                        // Default to just the component breakdown unless it's hour assignment
                        let finalSubDesc = subDesc;

                        if (subDesc.toLowerCase() === 'u') {
                            subUnit = 'h';
                            subMinsPerUnit = 60; // 1 hour = 60 minutes
                            finalSubDesc = "Heures (u)";
                        } else {
                            if (subDesc.toLowerCase() === 'pc') subUnit = 'pc';
                            
                            const mappedMins = codeToMinutesMap.get(subDesc.toUpperCase());
                            if (mappedMins !== undefined) {
                                subMinsPerUnit = mappedMins;
                            }
                        }

                        // Total component quantity = Parent Quantity * Component Quantity
                        const totalComponentQty = qtyStr * subQty;

                        validTasks.push({
                            articleCode: techCode,
                            category: subCategory,
                            description: finalSubDesc,
                            unit: subUnit,
                            quantity: totalComponentQty,
                            completedQuantity: 0,
                            minutesPerUnit: subMinsPerUnit
                        });
                    }
                });
            } else {
                validTasks.push({
                    articleCode: techCode || rawArticle || null,
                    category: cat,
                    description: finalDesc,
                    unit: String(unit).trim(),
                    quantity: qtyStr,
                    completedQuantity: 0,
                    minutesPerUnit: minsStr
                });
            }
        }

        console.log(`Parsed ${validTasks.length} tasks from Excel.`);

        // 3. Ensure PM and SM users exist
        let pm = await prisma.user.findUnique({ where: { email: "pm@worksite.com" }});
        if (!pm) pm = await prisma.user.create({ data: { name: "PM Principal", email: "pm@worksite.com", passwordHash: "password", role: "PM" }});
        let sm = await prisma.user.findUnique({ where: { email: "sm@worksite.com" }});
        if (!sm) sm = await prisma.user.create({ data: { name: "Chef de Chantier Herlin", email: "sm@worksite.com", passwordHash: "password", role: "SM" }});

        // 4. Create Project
        const project = await prisma.project.create({
            data: {
                name: "🔥 EEG Pilote - CHU Namur (Simulation 12 Semaines)",
                location: "Namur, Belgique",
                projectManagerId: pm.id,
                siteManagerId: sm.id,
                tasks: {
                    create: validTasks
                }
            },
            include: { tasks: true }
        });
        console.log(`Created Project ${project.id}.`);

        // 5. Simulate 12 weeks of progress
        console.log("Simulating 12 weeks of work...");
        let currentWeek = 10;
        let year = 2026;

        // Spread the tasks out over 12 weeks
        // Group them by category roughly
        const tasksByCategory = {};
        project.tasks.forEach(t => {
            if (!tasksByCategory[t.category]) tasksByCategory[t.category] = [];
            tasksByCategory[t.category].push(t);
        });
        
        const categories = Object.keys(tasksByCategory);
        let categoryIndex = 0;

        for (let w = 1; w <= 12; w++) {
            // For each week, pick 20-30 random uncompleted tasks, or from a specific category
            const weekTasks = [];
            let plannedHours = 0;
            const targetWeeklyHours = 200 + Math.random() * 100; // 200 - 300 hrs capacity

            // Try to pull tasks from current category
            let currentCatTasks = tasksByCategory[categories[categoryIndex % categories.length]];
            
            for (const t of currentCatTasks) {
                const remaining = t.quantity - t.completedQuantity;
                if (remaining <= 0) continue;

                // Grab a chunk of it
                const simulateQty = Math.min(remaining, Math.ceil(remaining * (0.3 + Math.random() * 0.7))); 
                const hrs = (simulateQty * t.minutesPerUnit) / 60;
                
                weekTasks.push({
                    taskId: t.id,
                    plannedQuantity: simulateQty,
                    actualQuantity: 0 // Will fill
                });

                plannedHours += hrs;
                if (plannedHours > targetWeeklyHours) break;
            }

            categoryIndex++;

            if (weekTasks.length === 0) continue;

            const workers = Math.ceil(targetWeeklyHours / 40);

            // Create Weekly Plan
            const plan = await prisma.weeklyPlan.create({
                data: {
                    projectId: project.id,
                    weekNumber: currentWeek,
                    year: year,
                    numberOfWorkers: workers,
                    targetHoursCapacity: workers * 40,
                    hasDrawings: true,
                    hasTools: true,
                    hasMaterials: true,
                    isSubmitted: true, // It's in the past
                    targetReached: (Math.random() > 0.4), // 60% success rate
                    issuesReported: (Math.random() > 0.7) ? "Retard de livraison du fournisseur." : null
                }
            });

            // Add tasks and update DB actual completions
            for (const wt of weekTasks) {
                // Actual is usually 80-110% of planned
                const performance = 0.8 + (Math.random() * 0.3);
                let actual = Math.floor(wt.plannedQuantity * performance);
                
                if (actual > wt.plannedQuantity) actual = wt.plannedQuantity; // Don't over-complete easily for the script

                await prisma.weeklyPlanTask.create({
                    data: {
                        weeklyPlanId: plan.id,
                        taskId: wt.taskId,
                        plannedQuantity: wt.plannedQuantity,
                        actualQuantity: actual
                    }
                });

                // Update the task's completed quantity natively
                await prisma.task.update({
                    where: { id: wt.taskId },
                    data: { completedQuantity: { increment: actual } }
                });
            }

            console.log(`- Week ${w}/12 simulated. [Week ${currentWeek}, ${year}] Planned ${plannedHours.toFixed(1)} hrs.`);

            currentWeek++;
            if (currentWeek > 52) {
                currentWeek = 1;
                year++;
            }
        }

        console.log("✅ Pilot Project fully simulated and injected!");

    } catch(e) {
        console.error("FATAL:", e);
    } finally {
        await prisma.$disconnect();
    }
}

function escapeObj(o) {
    if (o === undefined || o === null) return "";
    return String(o).trim();
}

